    }

    public static void testOrderManager(){
      System.out.println("Running testOrderManager .. ");
      OrderManager orderManager = new OrderManager();
      orderManager.addOrder(new Order(1,10,100,25.0, 3.2, OrderStatus.PLACED));
      orderManager.addOrder(new Order(2,10,101,55.0, 1.4, OrderStatus.PREPARING));
