        this.name = name;
        this.price = price;
        this.category = category;
        this.stockQty = stockQty;
    }

    public double getPrice() {
        return price;
    }

    public int getStockQty() {
        return stockQty;
    }

    public void setStockQty(int qty) {
        this.stockQty = qty;
    }

    @Override
    public String toString() {
        return "Product{id=" + productId + ", name='" + name + "', price=" + price + ", category=" + category + ", stock=" + stockQty + "}";
    }
}

