class AccountManager {
    private Map<Integer, Account> accounts;

    public AccountManager() {
        accounts = new HashMap<>();
    }

    public void addAccount(Account acc) {
        accounts.put(acc.accountId, acc);
    }

    public Account getAccount(int accId) {
        return accounts.get(accId);
    }

    public void updateBalance(int accId, double delta) {
        Account acc = getAccount(accId);
        if (acc != null) {
            if (delta > 0) {
                acc.deposit(delta);
            } else {
                acc.withdraw(-delta);
            }
        }
    }
}

class TransactionManager {
    private List<Transaction> transactions;
    private AccountManager accountMgr;

    public TransactionManager(AccountManager accountMgr) {
        this.transactions = new ArrayList<>();
        this.accountMgr = accountMgr;
    }

    public void addTransaction(Transaction txn) {
        transactions.add(txn);
        processTransaction(txn);
    }

    private void processTransaction(Transaction txn) {
        boolean success = false;
        switch (txn.type) {
            case DEPOSIT:
                accountMgr.updateBalance(txn.toAccountId, txn.amount);
                success = true;
                break;
            case WITHDRAWAL:
                success = accountMgr.getAccount(txn.fromAccountId) != null && accountMgr.getAccount(txn.fromAccountId).withdraw(txn.amount);
                break;
            case TRANSFER:
                Account from = accountMgr.getAccount(txn.fromAccountId);
                if (from != null && from.withdraw(txn.amount)) {
                    accountMgr.updateBalance(txn.toAccountId, txn.amount);
                    success = true;
                }
                break;
        }
        txn.setStatus(success ? TransactionStatus.SUCCESS : TransactionStatus.FAILED);
    }

    public List<Transaction> getTransactions() {
        return transactions;
    }

    public int getTotalTransactions() {
        return transactions.size();
    }

    public double getTotalVolume() {
        return transactions.stream().mapToDouble(t -> t.amount).sum();
    }

    public double getAvgAmount() {
        return getTotalVolume() / Math.max(1, getTotalTransactions());
    }
}

class FraudMonitor {
    private TransactionManager txnMgr;
    private static final double HIGH_AMOUNT_THRESHOLD = 10000.0;
    private static final int MAX_TXNS_PER_ACCOUNT = 5;

    public FraudMonitor(TransactionManager txnMgr) {
        this.txnMgr = txnMgr;
    }

    public AlertLevel checkTransaction(Transaction txn) {
        if (txn.amount > HIGH_AMOUNT_THRESHOLD) {
            return AlertLevel.HIGH;
        }
        long countFrom = txnMgr.getTransactions().stream()
            .filter(t -> t.fromAccountId == txn.fromAccountId && t.status == TransactionStatus.SUCCESS)
            .count();
        if (countFrom > MAX_TXNS_PER_ACCOUNT) {
            return AlertLevel.MEDIUM;
        }
        return AlertLevel.LOW;
    }

    public int getFraudCount() {
        return (int) txnMgr.getTransactions().stream()
            .filter(t -> checkTransaction(t) != AlertLevel.LOW)
            .count();
    }
}

