public class Run {
    private int[] obstacleTimes;

    public Run(int[] obstacleTimes) {
        this.obstacleTimes = obstacleTimes != null ? obstacleTimes.clone() : new int[0];
    }

    public int getTotalTime() {
        int total = 0;
        for (int time : obstacleTimes) {
            total += time;
        }
        return total;
    }

    public boolean isComplete(int numObstacles) {
        return obstacleTimes.length == numObstacles;
    }

    public int getTime(int obstacleIdx) {
        if (obstacleIdx >= 0 && obstacleIdx < obstacleTimes.length) {
            return obstacleTimes[obstacleIdx];
        }
        return -1; // or throw exception
    }

    public int getNumObstaclesCompleted() {
        return obstacleTimes.length;
    }

    public int[] getObstacleTimes() {
        return obstacleTimes.clone();
    }
}


import java.util.*;

public class RunCollection {
    private List<Run> runs;
    private int numObstacles;

    public RunCollection(int numObstacles) {
        this.runs = new ArrayList<>();
        this.numObstacles = numObstacles;
    }

    public void addRun(Run run) {
        runs.add(run);
    }

    public int getNumRuns() {
        return runs.size();
    }

    public int getNumObstacles() {
        return numObstacles;
    }

    public double averageTimePerObstacle(int obsIdx) {
        if (obsIdx < 0 || obsIdx >= numObstacles) return 0.0;

        double sum = 0.0;
        int count = 0;
        for (Run run : runs) {
            int time = run.getTime(obsIdx);
            if (time != -1) { // completed this obstacle
                sum += time;
                count++;
            }
        }
        return count > 0 ? sum / count : 0.0;
    }

    public int getTotalTime(int runIdx) {
        if (runIdx >= 0 && runIdx < runs.size()) {
            return runs.get(runIdx).getTotalTime();
        }
        return 0;
    }

    public Run getFastestCompleteRun() {
        Run fastest = null;
        int minTime = Integer.MAX_VALUE;
        for (Run run : runs) {
            if (run.isComplete(numObstacles)) {
                int total = run.getTotalTime();
                if (total < minTime) {
                    minTime = total;
                    fastest = run;
                }
            }
        }
        return fastest;
    }

    public void printStats() {
        System.out.println("Obstacle Averages:");
        for (int i = 0; i < numObstacles; i++) {
            System.out.printf("Obs %02d: %.2f%n", i+1, averageTimePerObstacle(i));
        }
        System.out.println("\nRun Totals:");
        for (int i = 0; i < getNumRuns(); i++) {
            System.out.printf("Run %d: %d (complete: %s)%n", i+1, getTotalTime(i), runs.get(i).isComplete(numObstacles));
        }
        Run fastest = getFastestCompleteRun();
        if (fastest != null) {
            System.out.println("Fastest complete run total: " + fastest.getTotalTime());
        }
    }

    public List<Run> getRuns() {
        return new ArrayList<>(runs);
    }
}


